import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"モニタリングトラブルシューティング: リクエストログ分析 | Antigravity-Manager","description":"Antigravity Tools の Proxy Monitor モニタリングトラブルシューティングを学びます。リクエストログ、フィルタリング、詳細復元機能で 401/429/5xx エラーとストリーミング中断問題を特定します。","frontmatter":{"title":"モニタリングトラブルシューティング: リクエストログ分析 | Antigravity-Manager","sidebarTitle":"リクエストログでデバッグ","subtitle":"モニタリングトラブルシューティング: リクエストログ分析","description":"Antigravity Tools の Proxy Monitor モニタリングトラブルシューティングを学びます。リクエストログ、フィルタリング、詳細復元機能で 401/429/5xx エラーとストリーミング中断問題を特定します。","tags":["高度","モニタリング","トラブルシューティング","Proxy","ログ"],"prerequisite":["start-proxy-and-first-client","start-first-run-data","advanced-config"],"order":6},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"}'),i={name:"ja/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"};function d(l,t,s,n,c,p){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="proxy-monitor-リクエストログ、フィルタリング、詳細復元とエクスポート" tabindex="-1">Proxy Monitor：リクエストログ、フィルタリング、詳細復元とエクスポート <a class="header-anchor" href="#proxy-monitor-リクエストログ、フィルタリング、詳細復元とエクスポート" aria-label="Permalink to &quot;Proxy Monitor：リクエストログ、フィルタリング、詳細復元とエクスポート&quot;">​</a></h1><p>ローカルリバースプロキシは起動しましたが、401/429/500、ストリーミング中断、あるいは「なぜ突然アカウント/モデルが変わった」が発生すると、トラブルシューティングはすぐに当てずっぽうになりがちです。</p><p>このレッスンでは 1 つのことだけを解説します：<strong>Proxy Monitor</strong> を使って各呼び出しを「再現可能な証拠」に復元し、リクエストがどこから来たか、どのエンドポイントに打たれたか、どのアカウントを使用したか、モデルがマッピングされたか、そして Token 消費がどれくらいかを知ることです。</p><h2 id="このレッスンでできること" tabindex="-1">このレッスンでできること <a class="header-anchor" href="#このレッスンでできること" aria-label="Permalink to &quot;このレッスンでできること&quot;">​</a></h2><ul><li><code>/monitor</code> ページで録画を開始/一時停止し、Token Stats に影響するかどうかを理解</li><li>検索ボックス、クイックフィルタ、アカウントフィルタを使って 1 つのリクエスト記録を迅速に特定</li><li>詳細ポップアップで Request/Response メッセージを確認してコピーし、失敗原因を再検討</li><li>Proxy Monitor のデータ保存場所（<code>proxy_logs.db</code>）とクリア動作を知る</li><li>現在バージョンの「ログエクスポート」の実際の能力境界（GUI vs バックエンドコマンド）を理解</li></ul><h2 id="現在の悩み" tabindex="-1">現在の悩み <a class="header-anchor" href="#現在の悩み" aria-label="Permalink to &quot;現在の悩み&quot;">​</a></h2><ul><li>「呼び出し失敗/タイムアウト」しか見えないが、アップストリーム、プロキシ、クライアント設定のどこで失敗したかわからない</li><li>モデルマッピングまたはアカウントローテーションがトリガーされたと疑うが、証拠チェーンがない</li><li>1 つのリクエストの完全な payload（特にストリーミング/Thinking）を再検討したいが、ログに見えない</li></ul><h2 id="この方法をいつ使うか" tabindex="-1">この方法をいつ使うか <a class="header-anchor" href="#この方法をいつ使うか" aria-label="Permalink to &quot;この方法をいつ使うか&quot;">​</a></h2><ul><li>トラブルシューティングが必要：401 認証失敗、429 レート制限、5xx アップストリームエラー、ストリーミング中断</li><li>確認したい：あるリクエストが実際にどのアカウントを使用したか（<code>X-Account-Email</code>）</li><li>モデルルーティング戦略を策定中、「クライアントモデル名 → 実際マッピングモデル名」を検証したい</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>Proxy Monitor が記録するのは「リバースプロキシサービスが受信したリクエスト」です。したがって、少なくともまず次のことを完了させる必要があります：</p><ul><li>リバースプロキシサービスが起動し、<code>/healthz</code> にアクセスできる</li><li>現在のリバースプロキシの Base URL とポートを知っている</li></ul><p>まだ動かない場合は、まず <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">ローカルリバースプロキシを起動して最初のクライアントを接続する</a></strong> を見てください。</p></div><h2 id="proxy-monitor-とは" tabindex="-1">Proxy Monitor とは？ <a class="header-anchor" href="#proxy-monitor-とは" aria-label="Permalink to &quot;Proxy Monitor とは？&quot;">​</a></h2><p><strong>Proxy Monitor</strong> は Antigravity Tools 内蔵の「リクエストログダッシュボード」です。各リクエストがローカルリバースプロキシに入ると、時間、パス、ステータスコード、所要時間、モデルとプロトコルを記録し、可能な限りレスポンスから Token 使用量を抽出します。また、単一の記録を開いてリクエストとレスポンスメッセージを確認し、失敗原因とルーティング/アカウント選択結果を再検討できます。</p><div class="info custom-block"><p class="custom-block-title">データ保存場所</p><p>Proxy Monitor のログはデータディレクトリ以下の SQLite に書き込まれます：<code>proxy_logs.db</code>。データディレクトリの探し方とバックアップ方法は、先に <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/first-run-data/">初回起動時の必知事項：データディレクトリ、ログ、トレイ、自動起動</a></strong> を復習してください。</p></div><h2 id="コアコンセプト-注意すべき-6-つのフィールド" tabindex="-1">コアコンセプト：注意すべき 6 つのフィールド <a class="header-anchor" href="#コアコンセプト-注意すべき-6-つのフィールド" aria-label="Permalink to &quot;コアコンセプト：注意すべき 6 つのフィールド&quot;">​</a></h2><p>Proxy Monitor の 1 つの記録（バックエンド構造体 <code>ProxyRequestLog</code>）で、最も実用的なのは以下のフィールドです：</p><table tabindex="0"><thead><tr><th>フィールド</th><th>それで何の質問に答えるか</th></tr></thead><tbody><tr><td><code>status</code></td><td>今回のリクエストは成功か失敗か（200-399 vs その他）</td></tr><tr><td><code>url</code> / <code>method</code></td><td>どのエンドポイントに打たれたか（例：<code>/v1/messages</code>、<code>/v1/chat/completions</code>）</td></tr><tr><td><code>protocol</code></td><td>これは OpenAI / Claude(Anthropic) / Gemini のどのプロトコルか</td></tr><tr><td><code>account_email</code></td><td>今回のリクエストで最終的にどのアカウントが使われたか（<code>X-Account-Email</code> レスポンスヘッダから）</td></tr><tr><td><code>model</code> / <code>mapped_model</code></td><td>クライアントがリクエストしたモデル名が別のモデルに「ルーティング/マッピング」されたか</td></tr><tr><td><code>input_tokens</code> / <code>output_tokens</code></td><td>今回のリクエストの Token 使用量（抽出できた場合のみ）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">まず「概要」を使い、必要に応じて「詳細」を開く</p><p>リストページは概要のみを表示（request/response body なし）。1 つの記録を開くと、バックエンドから完全な詳細を読み込みます。これでリストが一度に大きなフィールドを引きすぎることを避けます。</p></div><h2 id="さあ、一緒にやってみよう-1-回の呼び出しで「モニタリングループ」を完成" tabindex="-1">さあ、一緒にやってみよう：1 回の呼び出しで「モニタリングループ」を完成 <a class="header-anchor" href="#さあ、一緒にやってみよう-1-回の呼び出しで「モニタリングループ」を完成" aria-label="Permalink to &quot;さあ、一緒にやってみよう：1 回の呼び出しで「モニタリングループ」を完成&quot;">​</a></h2><h3 id="ステップ-1-まず「必ず現れる」リクエストを作成" tabindex="-1">ステップ 1：まず「必ず現れる」リクエストを作成 <a class="header-anchor" href="#ステップ-1-まず「必ず現れる」リクエストを作成" aria-label="Permalink to &quot;ステップ 1：まず「必ず現れる」リクエストを作成&quot;">​</a></h3><p><strong>なぜ</strong> Proxy Monitor はリバースプロキシサービスが受信したリクエストのみを記録します。まず最もシンプルなリクエストで「記録があるか」を検証し、その後フィルタリングと詳細について話します。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-3dY71" id="tab-otmhJwv" checked><label data-title="macOS/Linux" for="tab-otmhJwv">macOS/Linux</label><input type="radio" name="group-3dY71" id="tab-ZeuD-vM"><label data-title="Windows" for="tab-ZeuD-vM">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) ヘルスチェック（必ず存在するエンドポイント）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) もう一度 models をリクエスト（認証を有効にした場合、header を忘れずに）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) ヘルスチェック（必ず存在するエンドポイント）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) もう一度 models をリクエスト（認証を有効にした場合、header を忘れずに）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div></div></div><p><strong>期待される結果</strong>：端末から <code>{&quot;status&quot;:&quot;ok&quot;}</code>（または類似の JSON）と <code>/v1/models</code> のレスポンス（成功でも 401 でも可）が返される。</p><h3 id="ステップ-2-monitor-ページを開いて「録画状態」を確認" tabindex="-1">ステップ 2：Monitor ページを開いて「録画状態」を確認 <a class="header-anchor" href="#ステップ-2-monitor-ページを開いて「録画状態」を確認" aria-label="Permalink to &quot;ステップ 2：Monitor ページを開いて「録画状態」を確認&quot;">​</a></h3><p><strong>なぜ</strong> Proxy Monitor には「録画/一時停止」スイッチがあります。現在の状態をまず確認しないと、ずっとリクエストしているがリストがずっと空ということがあります。</p><p>Antigravity Tools でサイドバーの <strong>API モニタリングダッシュボード</strong>（ルートは <code>/monitor</code>）を開く。</p><p>ページ上部にドット付きボタンがあるはずです：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ● 録画中   [検索ボックス]  [更新] [クリア]      │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span></code></pre></div><p>「一時停止中」が見えたら、一度クリックして「録画中」に切り替える。</p><p><strong>期待される結果</strong>：ボタン状態が「録画中」に変わる；リストに直前のリクエスト記録が現れ始める。</p><h3 id="ステップ-3-「検索-クイックフィルタ」で-1-つの記録を特定" tabindex="-1">ステップ 3：「検索 + クイックフィルタ」で 1 つの記録を特定 <a class="header-anchor" href="#ステップ-3-「検索-クイックフィルタ」で-1-つの記録を特定" aria-label="Permalink to &quot;ステップ 3：「検索 + クイックフィルタ」で 1 つの記録を特定&quot;">​</a></h3><p><strong>なぜ</strong> 実際のトラブルシューティングでは、通常 1 つのフラグメントしか覚えていません：パスに <code>messages</code> がある、またはステータスコードが <code>401</code> である、またはモデル名に <code>gemini</code> がある。検索ボックスはこのような記憶のために設計されています。</p><p>Proxy Monitor の検索は、あなたの入力を「ファジーキーワード」として扱い、バックエンドで SQL <code>LIKE</code> でこれらのフィールドにマッチします：</p><ul><li><code>url</code></li><li><code>method</code></li><li><code>model</code></li><li><code>status</code></li><li><code>account_email</code></li></ul><p>いくつかの典型的なキーワードを試すことができます：</p><ul><li><code>healthz</code></li><li><code>models</code></li><li><code>401</code>（ちょうど 401 を作成した場合）</li></ul><p>また「クイックフィルタ」ボタンをクリックすることもできます：<strong>エラーのみ / Chat / Gemini / Claude / 画像生成</strong>。</p><p><strong>期待される結果</strong>：リストにあなたが期待した種類のリクエストのみが残る。</p><h3 id="ステップ-4-詳細を開いて「リクエストメッセージ-レスポンスメッセージ」を復元" tabindex="-1">ステップ 4：詳細を開いて「リクエストメッセージ + レスポンスメッセージ」を復元 <a class="header-anchor" href="#ステップ-4-詳細を開いて「リクエストメッセージ-レスポンスメッセージ」を復元" aria-label="Permalink to &quot;ステップ 4：詳細を開いて「リクエストメッセージ + レスポンスメッセージ」を復元&quot;">​</a></h3><p><strong>なぜ</strong> リストは「何が起きたか」に答えるには十分ですが、「なぜ」に答えるには、通常完全なリクエスト/レスポンス payload を見る必要があります。</p><p>任意の記録を開くと、詳細ウィンドウがポップアップします。以下を重点的に確認できます：</p><ul><li><code>プロトコル</code>（OpenAI/Claude/Gemini）</li><li><code>使用モデル</code> と <code>マッピングモデル</code></li><li><code>使用アカウント</code></li><li><code>Token 消費 (入力/出力)</code></li></ul><p>その後ボタンでコピー：</p><ul><li><code>リクエストメッセージ (Request)</code></li><li><code>レスポンスメッセージ (Response)</code></li></ul><p><strong>期待される結果</strong>：詳細に 2 つの JSON（またはテキスト）プレビューがある；コピー後、チケット/メモに貼り付けて再検討できます。</p><h3 id="ステップ-5-「ゼロから再現」が必要な場合、ログをクリア" tabindex="-1">ステップ 5：「ゼロから再現」が必要な場合、ログをクリア <a class="header-anchor" href="#ステップ-5-「ゼロから再現」が必要な場合、ログをクリア" aria-label="Permalink to &quot;ステップ 5：「ゼロから再現」が必要な場合、ログをクリア&quot;">​</a></h3><p><strong>なぜ</strong> トラブルシューティング時、最も怖いのは「古いデータが判断を干渉する」ことです。クリア後にもう一度再現すると、成功/失敗が非常に明確になります。</p><p>上部の「クリア」ボタンをクリックすると、確認ダイアログがポップアップします。</p><div class="danger custom-block"><p class="custom-block-title">これは不可逆操作</p><p>クリアは <code>proxy_logs.db</code> 内のすべての記録を削除します。</p></div><p><strong>期待される結果</strong>：確認後リストがクリアされ、統計数字が 0 に戻る。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] <code>/monitor</code> で自分が送ったばかりの <code>/healthz</code> または <code>/v1/models</code> 記録が見える</li><li>[ ] 検索ボックスで 1 つの記録をフィルタリングできる（例：<code>healthz</code> を入力）</li><li>[ ] 1 つの記録を開いてリクエスト/レスポンスメッセージを見てコピーできる</li><li>[ ] ログをクリアするとすべての履歴記録が直接削除されることを知っている</li></ul><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>あなたが理解するかもしれないこと（❌）</th><th>実際の挙動（✓）</th></tr></thead><tbody><tr><td>「一時停止中」= モニタリングオーバーヘッドが完全にない</td><td>一時停止後リクエストが解析されないと思っている</td><td>一時停止は「Proxy Monitor ログに書き込むかどうか」のみに影響。しかしリクエスト/レスポンス解析（ストリーミングデータの SSE 解析を含む）は依然として発生し、解析後のデータは保存されないだけ。Token Stats も依然として記録（モニタリングが有効かどうかにかかわらず）。</td></tr><tr><td>バイナリ/大きなペイロードログが空</td><td>モニタリングが壊れたと思っている</td><td>バイナリリクエスト/レスポンスは <code>[Binary Request Data]</code> / <code>[Binary Response Data]</code> と表示される。レスポンスボディが 100MB を超えると <code>[Response too large (&gt;100MB)]</code> とマーク；リクエストボディが制限を超えると記録されない。</td></tr><tr><td>Monitor で「誰がリクエストを開始したか」を見つけたい</td><td>クライアントプロセスまで追跡できると思っている</td><td>Monitor は HTTP 層情報（メソッド/パス/モデル/アカウント）を記録し、「呼び出し元プロセス名」は含まない。クライアント自身のログまたはシステムネットワークキャプチャと組み合わせてソースを特定する必要がある。</td></tr><tr><td>モニタリング有効時に Token Stats データが異常</td><td>統計エラーだと思っている</td><td>モニタリング有効時、Token Stats が 2 回記録される可能性がある（1 回はモニタリング関数の先頭、1 回は非同期でデータベースに書き込む時）。これは現在バージョンのソースコードの挙動です。</td></tr></tbody></table><h2 id="エクスポートと長期保存-まず能力境界を明確に" tabindex="-1">エクスポートと長期保存：まず能力境界を明確に <a class="header-anchor" href="#エクスポートと長期保存-まず能力境界を明確に" aria-label="Permalink to &quot;エクスポートと長期保存：まず能力境界を明確に&quot;">​</a></h2><h3 id="_1-gui-で現在何ができるか" tabindex="-1">1) GUI で現在何ができるか <a class="header-anchor" href="#_1-gui-で現在何ができるか" aria-label="Permalink to &quot;1) GUI で現在何ができるか&quot;">​</a></h3><p>現在バージョンの Monitor UI（<code>ProxyMonitor.tsx</code>）では、以下ができます：</p><ul><li>検索/フィルタリング/ページング参照</li><li>詳細を開いて payload を確認してコピー</li><li>すべてのログをクリア</li></ul><p>しかし <strong>「エクスポートボタン」は見つからない</strong>（ソースコードに該当する UI が見つからない）。</p><h3 id="_2-バックエンドにどのようなエクスポート能力があるか-二次開発向け" tabindex="-1">2) バックエンドにどのようなエクスポート能力があるか（二次開発向け） <a class="header-anchor" href="#_2-バックエンドにどのようなエクスポート能力があるか-二次開発向け" aria-label="Permalink to &quot;2) バックエンドにどのようなエクスポート能力があるか（二次開発向け）&quot;">​</a></h3><p>バックエンド Tauri コマンドは 2 種類のエクスポート方式を提供します：</p><ul><li><code>export_proxy_logs(file_path)</code>：データベース内の「すべてのログ」を JSON ファイルにエクスポート</li><li><code>export_proxy_logs_json(file_path, json_data)</code>：あなたが入力した JSON 配列を整形してファイルに書き込み（入力は配列形式である必要がある）</li></ul><p>GUI を二次開発したい場合、または自分の呼び出しスクリプトを書きたい場合、これらのコマンドを直接再利用できます。</p><h3 id="_3-最もシンプルな「エクスポート」-proxy-logs-db-を直接バックアップ" tabindex="-1">3) 最もシンプルな「エクスポート」：<code>proxy_logs.db</code> を直接バックアップ <a class="header-anchor" href="#_3-最もシンプルな「エクスポート」-proxy-logs-db-を直接バックアップ" aria-label="Permalink to &quot;3) 最もシンプルな「エクスポート」：\`proxy_logs.db\` を直接バックアップ&quot;">​</a></h3><p>Proxy Monitor は本質的に SQLite なので、<code>proxy_logs.db</code> を「トラブルシューティング証拠パッケージ」として一緒にバックアップすることもできます（例：<code>token_stats.db</code> と一緒に）。データディレクトリ位置は <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/first-run-data/">初回起動時の必知事項</a></strong> を参照。</p><h2 id="おすすめ関連記事" tabindex="-1">おすすめ関連記事 <a class="header-anchor" href="#おすすめ関連記事" aria-label="Permalink to &quot;おすすめ関連記事&quot;">​</a></h2><ul><li>モデルマッピングを明確にしたい場合：<strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/advanced/model-router/">モデルルーティング：カスタムマッピング、ワイルドカード優先順位とプリセット戦略</a></strong></li><li>認証問題をトラブルシューティングしたい場合：<strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/faq/auth-401/">401/認証失敗：auth_mode、Header 互換性とクライアント設定チェックリスト</a></strong></li><li>Monitor とコスト統計を組み合わせたい場合：次のセクションで Token Stats（<code>token_stats.db</code>）を解説</li></ul><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Proxy Monitor の価値は「再現可能」：ステータスコード/パス/プロトコル/アカウント/モデルマッピング/Token 使用量を記録し、リクエスト詳細を提供</li><li>検索とクイックフィルタがトラブルシューティングエントリ：まず範囲を縮小し、その後詳細を開いて payload を見る</li><li>ログをクリアすることは不可逆操作；エクスポートは現在「二次開発能力」と「データベースファイルバックアップ」に傾いている</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/advanced/token-stats/">Token Stats：コスト視点の統計指標とチャート解説</a></strong> を学びます。「高い気がする」を定量化可能な最適化に変えます。</p></blockquote><hr><h2 id="付録-ソースコード参考" tabindex="-1">付録：ソースコード参考 <a class="header-anchor" href="#付録-ソースコード参考" aria-label="Permalink to &quot;付録：ソースコード参考&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの位置を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Monitor ページエントリ（ProxyMonitor をマウント）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Monitor.tsx#L1-L12" target="_blank" rel="noreferrer"><code>src/pages/Monitor.tsx</code></a></td><td>1-12</td></tr><tr><td>Monitor UI：テーブル/フィルタ/詳細ポップアップ</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L13-L713" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>13-713</td></tr><tr><td>UI：設定を読み込み enable_logging を同期</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L174-L243" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>174-243</td></tr><tr><td>UI：録画切り替え（config 書き込み + set_proxy_monitor_enabled）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L254-L267" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>254-267</td></tr><tr><td>UI：リアルタイムイベント監視（proxy://request）と重複排除</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L273-L355" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>273-355</td></tr><tr><td>UI：ログクリア（clear_proxy_logs）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L389-L403" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>389-403</td></tr><tr><td>UI：単一詳細ロード（get_proxy_log_detail）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L505-L519" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>505-519</td></tr><tr><td>モニタリングミドルウェア：リクエスト/レスポンス取得、token 解析、monitor に書き込み</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L13-L337" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>13-337</td></tr><tr><td>ProxyMonitor：enabled スイッチ、DB 書き込み、イベント送信</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L33-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>33-194</td></tr><tr><td>サーバー側モニタリングミドルウェアマウント（layer）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L183-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>183-194</td></tr><tr><td>Tauri コマンド：get/count/filter/detail/clear/export</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/proxy.rs#L180-L314" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/proxy.rs</code></a></td><td>180-314</td></tr><tr><td>SQLite：proxy_logs.db パス、テーブル構造とフィルタ SQL</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L1-L416" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>1-416</td></tr><tr><td>モニタリング設計説明（実装と異なる可能性あり、ソースコードを優先）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-monitor-technical.md#L1-L53" target="_blank" rel="noreferrer"><code>docs/proxy-monitor-technical.md</code></a></td><td>1-53</td></tr></tbody></table><p><strong>キー定数</strong>：</p><ul><li><code>MAX_REQUEST_LOG_SIZE = 100 * 1024 * 1024</code>：モニタリングミドルウェアが読み取れる最大リクエストボディ（超えると読み取り失敗）</li><li><code>MAX_RESPONSE_LOG_SIZE = 100 * 1024 * 1024</code>：モニタリングミドルウェアが読み取れる最大レスポンスボディ（画像など大きなレスポンス用）</li></ul><p><strong>キー関数/コマンド</strong>：</p><ul><li><code>monitor_middleware(...)</code>：HTTP 層でリクエストとレスポンスを収集し、<code>monitor.log_request(...)</code> を呼び出す</li><li><code>ProxyMonitor::log_request(...)</code>：メモリ + SQLite に書き込み、<code>proxy://request</code> イベントで概要をプッシュ</li><li><code>get_proxy_logs_count_filtered(filter, errors_only)</code> / <code>get_proxy_logs_filtered(...)</code>：リストページフィルタリングとページング</li><li><code>get_proxy_log_detail(log_id)</code>：単一ログの完全な request/response body をロード</li><li><code>export_proxy_logs(file_path)</code>：全量ログを JSON ファイルにエクスポート（現在 UI はボタンを公開していない）</li></ul></details>`,74)])])}const u=o(i,[["render",d]]);export{g as __pageData,u as default};
